// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdbool.h>
#define MAX 1000000
bool isPrime[MAX + 1];
void sieveOfEratosthenes() {
    for (int i = 0; i <= MAX; i++) {
        isPrime[i] = true;
    }
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i <= MAX; i++) {
        if (isPrime[i]) {
            for (int j = i * i; j <= MAX; j += i) {
                isPrime[j] = false;
            }
        }
    }
}
int main() {
    int N, Q;
    scanf("%d", &N);
    int a[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &a[i]);
    }
    scanf("%d", &Q);
    sieveOfEratosthenes();
    for (int i = 0; i < Q; i++) {
        int L, R, X, Y;
        scanf("%d %d %d %d", &L, &R, &X, &Y);
        int result = 0;
        for (int j = X; j <= Y; j++) {
            if (isPrime[j]) {
                for (int k = L - 1; k < R; k++) {
                    int exponent = 0;
                    int number = a[k];
                    while (number % j == 0) {
                        exponent++;
                        number /= j;
                    }
                    result += exponent;
                }
            }
        }
        printf("%d\n", result);
    }
    return 0;
}

