// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static boolean[] isPrime = new boolean[1000001];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] a = new int[N];
        for (int i = 0; i < N; i++) {
            a[i] = sc.nextInt();
        }
        int Q = sc.nextInt();
        sieveOfEratosthenes();
        for (int i = 0; i < Q; i++) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int X = sc.nextInt();
            int Y = sc.nextInt();
            int result = 0;
            for (int j = X; j <= Y; j++) {
                if (isPrime[j]) {
                    for (int k = L - 1; k < R; k++) {
                        int exponent = 0;
                        int number = a[k];
                        while (number % j == 0) {
                            exponent++;
                            number /= j;
                        }
                        result += exponent;
                    }
                }
            }
            System.out.println(result);
        }
    }
    public static void sieveOfEratosthenes() {
        for (int i = 0; i < isPrime.length; i++) {
            isPrime[i] = true;
        }
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i < isPrime.length; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j < isPrime.length; j += i) {
                    isPrime[j] = false;
                }
            }
        }
    }
}

